from collections import deque

# 基础队列操作：BFS 层序遍历二叉树
class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def level_order(root: TreeNode) -> list:
    if not root:
        return []

    result = []
    queue = deque([root])  # 初始化队列，根节点入队

    while queue:
        level_size = len(queue)
        current_level = []

        for _ in range(level_size):
            node = queue.popleft()  # O(1) 出队
            current_level.append(node.val)

            # 子节点入队
            if node.left:
                queue.append(node.left)   # O(1) 入队
            if node.right:
                queue.append(node.right)

        result.append(current_level)

    return result

from collections import deque
from heapq import heappush, heappop

# 双端队列：滑动窗口最大值（LeetCode 239）
def max_sliding_window(nums: list, k: int) -> list:
    # deque 存储索引，保持递减；队首为窗口最大值
    dq = deque()
    result = []

    for i, num in enumerate(nums):
        # 移除不在窗口内的元素
        if dq and dq[0] < i - k + 1:
            dq.popleft()

        # 移除所有小于当前元素的（它们不可能成为最大值）
        while dq and nums[dq[-1]] <= num:
            dq.pop()

        dq.append(i)

        # 窗口形成后开始记录结果
        if i >= k - 1:
            result.append(nums[dq[0]])

    return result

# 优先队列：合并 K 个有序链表
class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

    def __lt__(self, other):
        return self.val < other.val

def merge_k_lists(lists: list) -> ListNode:
    # 最小堆，按节点值排序
    heap = []
    for l in lists:
        if l:
            heappush(heap, l)

    dummy = ListNode(0)
    current = dummy

    while heap:
        node = heappop(heap)  # 弹出最小值节点
        current.next = node
        current = current.next

        if node.next:
            heappush(heap, node.next)  # 该链表的下一个节点入堆

    return dummy.next
